     1→const API_BASE = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8000";
     2→
     3→export class ApiError extends Error {
     4→  constructor(
     5→    public readonly status: number,
     6→    message: string,
     7→  ) {
     8→    super(message);
     9→    this.name = "ApiError";
    10→  }
    11→}
    12→
    13→/**
    14→ * Base fetch wrapper. Attaches the Bearer token from the environment/session
    15→ * and converts non-2xx responses into thrown ApiErrors.
    16→ *
    17→ * Components never call fetch directly — they use functions from lib/api/*.
    18→ */
    19→export async function apiFetch<T>(
    20→  path: string,
    21→  options: RequestInit = {},
    22→  token?: string,
    23→): Promise<T> {
    24→  const headers: Record<string, string> = {
    25→    "Content-Type": "application/json",
    26→    ...(options.headers as Record<string, string>),
    27→  };
    28→
    29→  if (token) {
    30→    headers["Authorization"] = `Bearer ${token}`;
    31→  }
    32→
    33→  const response = await fetch(`${API_BASE}${path}`, {
    34→    ...options,
    35→    headers,
    36→  });
    37→
    38→  if (!response.ok) {
    39→    let detail = response.statusText;
    40→    try {
    41→      const body = await response.json();
    42→      const raw = body?.detail ?? detail;
    43→      detail = typeof raw === "string" ? raw : JSON.stringify(raw);
    44→    } catch {
    45→      // leave detail as statusText
    46→    }
    47→    throw new ApiError(response.status, detail);
    48→  }
    49→
    50→  return response.json() as Promise<T>;
    51→}
    52→

